      infer: true,
    }),
    loaderOptions: { path: path.join(__dirname, '/i18n/'), watch: true },
  }),
  resolvers: [
    {
      use: HeaderResolver,
      useFactory: (configService: ConfigService<AllConfigType>) => {
        return [
          configService.get('app.headerLanguage', {
            infer: true,
          }),
        ];
      },
      inject: [ConfigService],
    },
  ],
  imports: [ConfigModule],
  inject: [ConfigService],
}),
```

## Key Configuration Details

- **Translation files location**: `src/i18n/` directory
- **Fallback language**: Configured via `app.fallbackLanguage` environment variable (default: `'en'`)
- **Language header**: Configured via `app.headerLanguage` environment variable (default: `'x-custom-lang'`)
- **Watch mode**: Enabled (`watch: true`) for hot-reload during development

## How to Add a New Translation String

### Step 1: Create/Update Translation Files

Translation files are stored in `src/i18n/` as JSON files organized by language code (e.g., `en/common.json`).

Example structure:
```
src/i18n/
├── en/
│   ├── common.json
│   ├── confirm-email.json
│   ├── reset-password.json
│   └── confirm-new-email.json
└── [other-language-codes]/
```

### Step 2: Add Your Translation Key

For example, to add a new translation in `src/i18n/en/common.json`:

```json
{
  "confirmEmail": "Confirm your email",
  "resetPassword": "Reset your password",
  "myNewTranslation": "My new translated text"
}
```

### Step 3: Use in Your Code

The i18n is used in **`nestjs-boilerplate/source/src/mail/mail.service.ts`** as an example:

```typescript
import { I18nContext } from 'nestjs-i18n';

async userSignUp(mailData: MailData<{ hash: string }>): Promise<void> {
  const i18n = I18nContext.current();
  let emailConfirmTitle: MaybeType<string>;

  if (i18n) {
    emailConfirmTitle = await i18n.t('common.confirmEmail');
  }
  // ... rest of the code
}
```

### Step 4: Request Translation with Language Header

When making requests, include the language header:

```bash
curl -H "x-custom-lang: en" http://localhost:3000/api/v1/endpoint
```

Or use a different language code:
```bash
curl -H "x-custom-lang: fr" http://localhost:3000/api/v1/endpoint
```

## Environment Variables

Configure these in your `.env` file:

```env
APP_FALLBACK_LANGUAGE=en
APP_HEADER_LANGUAGE=x-custom-lang
```

# User Domain Class vs Database Entity

## User Domain Class

The **User domain class** is located at `src/users/domain/user.ts` and serves as the business logic representation:

```typescript
export class User {
  @ApiProperty({ type: idType })
  id: number | string;

  @ApiProperty({ type: String, example: 'john.doe@example.com' })
  @Expose({ groups: ['me', 'admin'] })
  email: string | null;

  @Exclude({ toPlainOnly: true })
  password?: string;

  @ApiProperty({ type: String, example: 'email' })
  @Expose({ groups: ['me', 'admin'] })
  provider: string;

  @ApiProperty({ type: String, example: '1234567890' })
  @Expose({ groups: ['me', 'admin'] })
  socialId?: string | null;

  @ApiProperty({ type: String, example: 'John' })
  firstName: string | null;

  @ApiProperty({ type: String, example: 'Doe' })
  lastName: string | null;

  @ApiProperty({ type: () => FileType })
  photo?: FileType | null;

  @ApiProperty({ type: () => Role })
  role?: Role | null;

  @ApiProperty({ type: () => Status })
  status?: Status;

  @ApiProperty()
  createdAt: Date;

  @ApiProperty()
  updatedAt: Date;

  @ApiProperty()
  deletedAt: Date;
}
```

**Key Characteristics:**
- **Serialization-focused** – Uses `@Expose` and `@Exclude` decorators to control what gets serialized
- **API documentation** – Decorated with `@ApiProperty` for Swagger
- **Nested objects** – Contains `FileType`, `Role`, and `Status` as domain objects
- **Visibility control** – Uses `groups` to selectively expose sensitive fields (email, provider, socialId)
- **Database-agnostic** – Works with both relational and document databases

